			return storage, err
		}
		storage[resource] = serviceCIDRStorage
		storage[resource+"/status"] = serviceCIDRStatusStorage
	}

	return storage, nil
}

func (p RESTStorageProvider) GroupName() string {
	return networking.GroupName
}

